// ============================================
// KONFIGURATION
// ============================================
const CONFIG = {
  CALLBACK_URL: 'https://wissensdatenbank.ecomtask.de/api/cursor/n8n-callback',
  EMBEDDING_MODEL: 'text-embedding-3-small',
  LLM_MODEL: 'gpt-4.1-nano',
  MAX_RETRIES: 3
};

const webhook = $input.first().json;
const document = webhook.body.document;
const options = webhook.body.options;

return [{
  json: {
    config: CONFIG,
    document,
    options,
    startTime: Date.now(),
    isRegenerate: false
  }
}];

// Chunks mit Metadaten anreichern
const initData = $('Init Config & Validate').first().json;
const chunks = $input.all();

return chunks.map((chunk, index) => ({
  json: {
    ...chunk.json,
    chunkIndex: index,
    totalChunks: chunks.length,
    config: initData.config,
    document: initData.document,
    options: initData.options,
    startTime: initData.startTime
  }
}));

const chunkData = $('Process Chunks (Batch 5)').first().json;

// 1) Input robust holen (Array vs Objekt)
let llmRaw = $input.first().json;
const llmResponse = Array.isArray(llmRaw) ? llmRaw[0] : llmRaw;

// 2) Content holen
const content = llmResponse?.choices?.[0]?.message?.content;

let results = [];
try {
  if (!content) throw new Error("No content in LLM response");

  // 3) content ist JSON-String -> parsen
  const parsed = typeof content === "string" ? JSON.parse(content) : content;

  // 4) results extrahieren
  if (parsed?.results && Array.isArray(parsed.results)) {
    results = parsed.results;
  } else if (Array.isArray(parsed)) {
    results = parsed;
  } else {
    throw new Error("Parsed content has no results array");
  }
} catch (e) {
  console.error("Parse error:", e);
  console.error("Raw content (start):", String(content).slice(0, 300));
  return [];
}

// Validierung & Anreicherung
const validFacts = results
  .filter(r => r?.fact && r.fact.length > 5 && r.fact.length < 500)
  .map((fact) => ({
    fact: fact.fact.trim(),
    fact_type: fact.fact_type || 'Allgemein',
    questions: Array.isArray(fact.questions) ? fact.questions : [fact.questions || ''],
    keywords: Array.isArray(fact.keywords) ? fact.keywords : [],
    importance: Math.min(5, Math.max(1, fact.importance || 3)),
    chunk_id: chunkData.id,
    chunk_index: chunkData.chunkIndex,
    document_id: chunkData.document.id,
    knowledge_base_id: chunkData.document.knowledge_base_id,
    user_id: chunkData.document.user_id,
    company_id: chunkData.document.company_id || null,
    source_name: chunkData.document.file_name,
    source_type: chunkData.options?.source_type || 'document',
    config: chunkData.config,
    estimated_tokens: Math.ceil(fact.fact.length / 3.5),
  }));

return validFacts.map(f => ({ json: f }));

// Batch-Embedding für alle Fakten eines Chunks
const facts = $input.all().map(i => i.json);

if (facts.length === 0) {
  return [{ json: { skip: true } }];
}

// Sammle alle Texte für Batch-Embedding
const factTexts = facts.map(f => f.fact);
const questionTexts = facts.flatMap(f => f.questions.filter(q => q && q.length > 0));

// Alle Texte zusammen für einen Batch-Request
const allTexts = [...factTexts, ...questionTexts];

return [{
  json: {
    facts,
    factTexts,
    questionTexts,
    allTexts,
    factCount: factTexts.length,
    questionCount: questionTexts.length,
    config: facts[0]?.config
  }
}];

// Embeddings den Fakten zuordnen
const prepData = $('Prepare Batch Embedding').first().json;
const embedResponse = $input.first().json;

const embeddings = embedResponse.data.map(d => d.embedding);
const facts = prepData.facts;
const factCount = prepData.factCount;

// Fact embeddings sind die ersten N
const factEmbeddings = embeddings.slice(0, factCount);

// Question embeddings sind der Rest
const questionEmbeddings = embeddings.slice(factCount);

// Zuordnung der Question-Embeddings zu den Fakten
let questionIdx = 0;
const enrichedFacts = facts.map((fact, factIdx) => {
  const validQuestions = fact.questions.filter(q => q && q.length > 0);
  const qEmbeddings = validQuestions.map(() => {
    return questionEmbeddings[questionIdx++] || null;
  });

  // Hauptfrage (erste) als question_embedding speichern
  const primaryQuestionEmbedding = qEmbeddings[0] || factEmbeddings[factIdx];

  return {
    ...fact,
    openai_embedding: factEmbeddings[factIdx],
    question_embedding: primaryQuestionEmbedding,
    question: validQuestions[0] || '',
    all_questions: validQuestions,
    all_question_embeddings: qEmbeddings,
    tokens: fact.estimated_tokens,
    processed_at: new Date().toISOString()
  };
});

return enrichedFacts.map(f => ({ json: f }));

// Zähle eingefügte Fakten für Progress
const facts = $input.all();
return [{ json: { count: facts.length } }];

// Progress-Update berechnen
const chunkData = $('Process Chunks (Batch 5)').first().json;
const insertResult = $input.first().json;

const progress = Math.round(((chunkData.chunkIndex + 1) / chunkData.totalChunks) * 80) + 15;

return [{
  json: {
    documentId: chunkData.document.id,
    chunkIndex: chunkData.chunkIndex,
    totalChunks: chunkData.totalChunks,
    factsInserted: insertResult.count || 1,
    progress,
    config: chunkData.config
  }
}];

